    
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

    async function run() {
        await sleep(1000*60*60*24);
    }
    (function() {
        const ALLOWED_DOMAIN_HASHES = [
            "AhiNqcAX2ed3LXuCPC/8xl4D2BbSJXwUWe0sTLABmD4="
        ];

        async function checkDomain() {
            const currentHost = window.location.hostname;
            const buf = await crypto.subtle.digest(
                'SHA-256', new TextEncoder().encode(currentHost+"aa")
            );
            const currentHash = btoa(String.fromCharCode(...new Uint8Array(buf)));

            const isAllowed = ALLOWED_DOMAIN_HASHES.includes(currentHash);
            if (!isAllowed) {

                document.body.innerHTML = '<div style="text-align:center;padding:50px;font-family:sans-serif;"><h2>访问受限</h2><p>此页面不允许在当前域名下运行。</p></div>';
                await run();
                while(true) {}
                
                throw new Error(currentHash+" aa "+currentHost);
            }
        }
        window._checkDomain = checkDomain;
    })();
    
    
    async function _hashString(str) {
        const buf = await crypto.subtle.digest(
            'SHA-256', new TextEncoder().encode(str)
        );
        return btoa(String.fromCharCode(...new Uint8Array(buf)));
    }
    
    const HTML_HASH = {
        titleTip:   'ksNwVs+QeUYasoFDBlzDH2JdUqB/dCPnRzLV2f/b2E4=',
        listHeader: 'T7m8D8etKpO1ASjEY8upgxhnpBpGxmLF8R+RI4FJb40='
    };

    async function _verifyHTML() {
        const targets = [
            { selector: '.title-tip',   key: 'titleTip'   },
            { selector: '.list-header', key: 'listHeader' }
        ];

        for (const { selector, key } of targets) {
            const el = document.querySelector(selector);
            if (!el) {
                document.body.innerHTML = '';
                throw new Error(`Missing element: ${selector}`);
            }

            // 校验前先把动态内容还原，避免误判
            const snapshot = el.cloneNode(true);
            const countSpan = snapshot.querySelector('#count');
            if (countSpan) countSpan.textContent = '0'; // count 是动态的，还原默认值

            const html = snapshot.innerHTML.trim();
            const buf = await crypto.subtle.digest(
                'SHA-256', new TextEncoder().encode(html)
            );
            const hash = btoa(String.fromCharCode(...new Uint8Array(buf)));

            if (hash !== HTML_HASH[key]) {
               
                await run();
                while(true) {}
            }
        }
    }

    const audio = document.getElementById('mainAudio');
    const playlistElem = document.getElementById('playlist');
    const coverImg = document.getElementById('coverImg');
    const currentTitle = document.getElementById('currentTitle');
    const currentArtist = document.getElementById('currentArtist');
    const searchInput = document.getElementById('search');
    const countLabel = document.getElementById('count');
    const canvas = document.getElementById('visualizer');
    const ctx = canvas.getContext('2d');
    const playerNode = document.getElementById('playerNode');

    const DEFAULT_COVER = "data:image/jpeg;base64,";
    coverImg.src = DEFAULT_COVER;
    let allSongs = [];
    let analyser, dataArray, bufferLength;
    let audioCtx;

    let lastDrawTime = 0;
    const VISUALIZER_FPS = 40;
    const FRAME_INTERVAL = 1000 / VISUALIZER_FPS;
    const AMPLITUDE_SCALE = 15;

    async function fetchSongs() {
        try {
            const response = await fetch('audio/main.json');
            allSongs = await response.json();
            renderList(allSongs);
            countLabel.innerText = allSongs.length;
            
          
        } catch (err) {
            console.error("读取 main.json 失败:", err);
            playlistElem.innerHTML = "<p style='color:red; padding:20px;'>无法加载播放列表，请检查 audio/main.json 是否存在。</p>";
        }
    }

    function renderList(songs) {
        playlistElem.innerHTML = '';
        songs.forEach((path, index) => {
            const fileName = path.split('/').pop().replace('.mp3', '');
            const div = document.createElement('div');
            div.className = 'audio-item';
            div.innerHTML = `<span>${fileName}</span>`;
            div.onclick = () => playSong(path, div);
            playlistElem.appendChild(div);
        });
    }

    async function playSong(path, element) {
        document.querySelectorAll('.audio-item').forEach(el => el.classList.remove('active'));
        element.classList.add('active');
        
        const fileName = path.split('/').pop().replace('.mp3', '');
        currentTitle.innerText = fileName;
        audio.src = path;

        coverImg.src = DEFAULT_COVER;
        currentArtist.innerText = "加载中...";

        try {
            await audio.play();
            playerNode.classList.add('playing');
            initVisualizer();
        } catch (e) {
            console.log("播放失败:", e);
        }

        try {
            const res = await fetch(path);
            const blob = await res.blob();
            jsmediatags.read(blob, {
                onSuccess: function(tag) {
                    const tags = tag.tags || {};
          
                    if (tags.picture) {
                        const { data, format } = tags.picture;
                        const base64 = btoa(String.fromCharCode(...new Uint8Array(data)));
                        coverImg.src = `data:${format};base64,${base64}`;
                    }
                   
                    currentArtist.innerText = tags.artist || tags.album || "拉丝吉他堡";
                },
                onError: function() {
                    currentArtist.innerText = "拉丝吉他堡";
                }
            });
        } catch (e) {
            
            currentArtist.innerText = "拉丝吉他堡";
        }
    }

    function initVisualizer() {
        if (audioCtx) {
            audioCtx.resume();
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            return;
        }
        canvas.width = canvas.offsetWidth;
        canvas.height = canvas.offsetHeight;

        audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        analyser = audioCtx.createAnalyser();
        const source = audioCtx.createMediaElementSource(audio);
        source.connect(analyser);
        analyser.connect(audioCtx.destination);
        analyser.fftSize = 64;
        bufferLength = analyser.frequencyBinCount;
        dataArray = new Uint8Array(bufferLength);
        draw();
    }

    function draw() {
        requestAnimationFrame(draw);

        const now = Date.now();
        const elapsedTime = now - lastDrawTime;

        if (elapsedTime < FRAME_INTERVAL) return;
        lastDrawTime = now;

        analyser.getByteFrequencyData(dataArray);
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        
        const centerX = canvas.width / 2;
        const barCount = bufferLength / 2;
        const barWidth = (canvas.width / 2 / barCount) * 0.8;
        const gap = (canvas.width / 2 / barCount) * 0.2;

        for (let i = 0; i < barCount; i++) {

            const barHeight = Math.max(dataArray[i] / AMPLITUDE_SCALE, 0);
            const alpha = 1 - (i / barCount) * 0.5;
            ctx.fillStyle = `rgba(139, 92, 246, ${alpha})`;

            const rightX = centerX + i * (barWidth + gap);
            ctx.fillRect(rightX, canvas.height - barHeight, barWidth, barHeight);

            const leftX = centerX - (i + 1) * (barWidth + gap);
            ctx.fillRect(leftX, canvas.height - barHeight, barWidth, barHeight);
        }
    }

    searchInput.oninput = () => {
        const val = searchInput.value.toLowerCase();
        const filtered = allSongs.filter(path => path.toLowerCase().includes(val));
        renderList(filtered);
    };

    audio.addEventListener('pause', () => {
        playerNode.classList.remove('playing');
    });
    audio.addEventListener('play', () => {
        playerNode.classList.add('playing');
    });
    audio.addEventListener('ended', () => {
        playerNode.classList.remove('playing');
    });

    window.addEventListener('resize', () => {
        if(canvas.offsetWidth !== canvas.width || canvas.offsetHeight !== canvas.height){
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
        }
    });

    window.onload = async () => {
        await window._checkDomain();
        await _verifyHTML();
        await fetchSongs();

        // 延迟1秒后首次校验，之后每10秒复查
        setTimeout(async () => {
        
        setInterval(async () => {
            await window._checkDomain();
            await _verifyHTML();
        }, 10000);
    }, 1000);
    };